29	    StreamTimeout_g         : t_areal                  := (1.0e-3, 1.0e-3);
30	    StreamClkFreq_g         : t_areal                  := (100.0e6, 100.0e6);
31	    StreamTsFifoDepth_g     : t_ainteger               := (16, 16);
32	    StreamUseTs_g           : t_abool                  := (true, true);
33	    -- Recording
34	    IntDataWidth_g          : positive                 := 64;
35	    MaxWindows_g            : positive range 1 to 32   := 16;
36	    MinBurstSize_g          : integer range 1 to 512   := 512;
37	    MaxBurstSize_g          : integer range 1 to 512   := 512;
38	    -- Axi
39	    AxiDataWidth_g          : natural range 64 to 1024 := 64;
40	    AxiMaxBurstBeats_g      : integer range 1 to 256   := 256;
