46	  port(
47	    -- Data Stream Input
48	    Str_Clk       : in  std_logic_vector(Streams_g - 1 downto 0);
49	    Str_Data      : in  t_aslv64(Streams_g - 1 downto 0);
50	    Str_Ts        : in  t_aslv64(Streams_g - 1 downto 0);
51	    Str_Vld       : in  std_logic_vector(Streams_g - 1 downto 0);
52	    Str_Rdy       : out std_logic_vector(Streams_g - 1 downto 0);
53	    Str_Trig      : in  std_logic_vector(Streams_g - 1 downto 0);
54	    -- Miscellaneous
55	    Irq           : out std_logic;
56	    -- AXI Slave Interface for Register Access
57	    S_Axi_Aclk    : in  std_logic;
58	    S_Axi_Aresetn : in  std_logic;
59	    S_Axi_ArId    : in  std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
60	    S_Axi_ArAddr  : in  std_logic_vector(15 downto 0);
61	    S_Axi_Arlen   : in  std_logic_vector(7 downto 0);
62	    S_Axi_ArSize  : in  std_logic_vector(2 downto 0);
63	    S_Axi_ArBurst : in  std_logic_vector(1 downto 0);
64	    S_Axi_ArLock  : in  std_logic;
65	    S_Axi_ArCache : in  std_logic_vector(3 downto 0);
66	    S_Axi_ArProt  : in  std_logic_vector(2 downto 0);
67	    S_Axi_ArValid : in  std_logic;
68	    S_Axi_ArReady : out std_logic;
69	    S_Axi_RId     : out std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
70	    S_Axi_RData   : out std_logic_vector(31 downto 0);
71	    S_Axi_RResp   : out std_logic_vector(1 downto 0);
72	    S_Axi_RLast   : out std_logic;
73	    S_Axi_RValid  : out std_logic;
74	    S_Axi_RReady  : in  std_logic;
75	    S_Axi_AwId    : in  std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
76	    S_Axi_AwAddr  : in  std_logic_vector(15 downto 0);
77	    S_Axi_AwLen   : in  std_logic_vector(7 downto 0);
78	    S_Axi_AwSize  : in  std_logic_vector(2 downto 0);
79	    S_Axi_AwBurst : in  std_logic_vector(1 downto 0);
80	    S_Axi_AwLock  : in  std_logic;
81	    S_Axi_AwCache : in  std_logic_vector(3 downto 0);
82	    S_Axi_AwProt  : in  std_logic_vector(2 downto 0);
83	    S_Axi_AwValid : in  std_logic;
84	    S_Axi_AwReady : out std_logic;
85	    S_Axi_WData   : in  std_logic_vector(31 downto 0);
86	    S_Axi_WStrb   : in  std_logic_vector(3 downto 0);
87	    S_Axi_WLast   : in  std_logic;
88	    S_Axi_WValid  : in  std_logic;
89	    S_Axi_WReady  : out std_logic;
90	    S_Axi_BId     : out std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
91	    S_Axi_BResp   : out std_logic_vector(1 downto 0);
92	    S_Axi_BValid  : out std_logic;
93	    S_Axi_BReady  : in  std_logic;
94	    -- AXI Master Interface for Memory Access
95	    M_Axi_Aclk    : in  std_logic;
96	    M_Axi_Aresetn : in  std_logic;
97	    M_Axi_AwAddr  : out std_logic_vector(31 downto 0);
98	    M_Axi_AwLen   : out std_logic_vector(7 downto 0);
99	    M_Axi_AwSize  : out std_logic_vector(2 downto 0);
100	    M_Axi_AwBurst : out std_logic_vector(1 downto 0);
101	    M_Axi_AwLock  : out std_logic;
102	    M_Axi_AwCache : out std_logic_vector(3 downto 0);
103	    M_Axi_AwProt  : out std_logic_vector(2 downto 0);
104	    M_Axi_AwValid : out std_logic;
105	    M_Axi_AwReady : in  std_logic                                     := '0';
106	    M_Axi_WData   : out std_logic_vector(AxiDataWidth_g - 1 downto 0);
107	    M_Axi_WStrb   : out std_logic_vector(AxiDataWidth_g / 8 - 1 downto 0);
108	    M_Axi_WLast   : out std_logic;
109	    M_Axi_WValid  : out std_logic;
110	    M_Axi_WReady  : in  std_logic                                     := '0';
111	    M_Axi_BResp   : in  std_logic_vector(1 downto 0)                  := (others => '0');
112	    M_Axi_BValid  : in  std_logic                                     := '0';
113	    M_Axi_BReady  : out std_logic;
114	    M_Axi_ArAddr  : out std_logic_vector(31 downto 0);
115	    M_Axi_ArLen   : out std_logic_vector(7 downto 0);
116	    M_Axi_ArSize  : out std_logic_vector(2 downto 0);
117	    M_Axi_ArBurst : out std_logic_vector(1 downto 0);
118	    M_Axi_ArLock  : out std_logic;
119	    M_Axi_ArCache : out std_logic_vector(3 downto 0);
120	    M_Axi_ArProt  : out std_logic_vector(2 downto 0);
121	    M_Axi_ArValid : out std_logic;
122	    M_Axi_ArReady : in  std_logic                                     := '0';
123	    M_Axi_RData   : in  std_logic_vector(AxiDataWidth_g - 1 downto 0) := (others => '0');
124	    M_Axi_RResp   : in  std_logic_vector(1 downto 0)                  := (others => '0');
125	    M_Axi_RLast   : in  std_logic                                     := '0';
126	    M_Axi_RValid  : in  std_logic                                     := '0';
127	    M_Axi_RReady  : out std_logic
128	  );
129	end entity;
130	
131	------------------------------------------------------------------------------
132	-- Architecture Declaration
133	------------------------------------------------------------------------------
134	architecture rtl of psi_ms_daq_axi is
135	
136	  -- Config Arrays with correct size
137	  constant StreamWidth_c       : t_ainteger(0 to Streams_g - 1) := StreamWidth_g(0 to Streams_g - 1);
138	  constant StreamPrio_c        : t_ainteger(0 to Streams_g - 1) := StreamPrio_g(0 to Streams_g - 1);
139	  constant StreamBuffer_c      : t_ainteger(0 to Streams_g - 1) := StreamBuffer_g(0 to Streams_g - 1);
140	  constant StreamTimeout_c     : t_areal(0 to Streams_g - 1)    := StreamTimeout_g(0 to Streams_g - 1);
141	  constant StreamClkFreq_c     : t_areal(0 to Streams_g - 1)    := StreamClkFreq_g(0 to Streams_g - 1);
142	  constant StreamTsFifoDepth_c : t_ainteger(0 to Streams_g - 1) := StreamTsFifoDepth_g(0 to Streams_g - 1);
143	  constant StreamUseTs_c       : t_abool(0 to Streams_g - 1)    := StreamUseTs_g(0 to Streams_g - 1);
144	
145	  -- Input/Statemachine Signals
146	  signal InpSm_HasTlast : std_logic_vector(Streams_g - 1 downto 0);
147	  signal InpSm_TsVld    : std_logic_vector(Streams_g - 1 downto 0);
148	  signal InpSm_TsRdy    : std_logic_vector(Streams_g - 1 downto 0);
149	  signal InpSm_Level    : t_aslv16(Streams_g - 1 downto 0);
150	  signal InpSm_TsData   : t_aslv64(Streams_g - 1 downto 0);
151	
152	  -- Statemachine/Dma
153	  signal SmDma_Cmd     : DaqSm2DaqDma_Cmd_t;
154	  signal SmDma_CmdVld  : std_logic;
155	  signal DmaSm_Resp    : DaqDma2DaqSm_Resp_t;
156	  signal DmaSm_RespVld : std_logic;
157	  signal DmaSm_RespRdy : std_logic;
158	  signal DmaSm_HasLast : std_logic_vector(Streams_g - 1 downto 0);
159	
160	  -- Input/Dma
161	  signal InpDma_Vld  : std_logic_vector(Streams_g - 1 downto 0);
162	  signal InpDma_Rdy  : std_logic_vector(Streams_g - 1 downto 0);
163	  signal InpDma_Data : Input2Daq_Data_a(Streams_g - 1 downto 0)(Data(IntDataWidth_g-1 downto 0), Bytes(log2ceil(IntDataWidth_g/8) downto 0));
164	
165	  -- Dma/Mem
166	  signal DmaMem_CmdAddr : std_logic_vector(31 downto 0);
167	  signal DmaMem_CmdSize : std_logic_vector(31 downto 0);
168	  signal DmaMem_CmdVld  : std_logic;
169	  signal DmaMem_CmdRdy  : std_logic;
170	  signal DmaMem_DatData : std_logic_vector(IntDataWidth_g-1 downto 0);
171	  signal DmaMem_DatVld  : std_logic;
172	  signal DmaMem_DatRdy  : std_logic;
173	
174	  -- Mem/Statemachine
175	  signal MemSm_Done : std_logic;
176	
177	  -- Configuration
178	  signal Cfg_StrEna    : std_logic_vector(Streams_g - 1 downto 0);
179	  signal Cfg_GlbEna    : std_logic;
180	  signal Cfg_PostTrig  : t_aslv32(Streams_g - 1 downto 0);
181	  signal Cfg_Arm       : std_logic_vector(Streams_g - 1 downto 0);
182	  signal Cfg_RecMode   : t_aslv2(Streams_g - 1 downto 0);
183	  signal Cfg_ToDisable : std_logic_vector(Streams_g -1 downto 0);
184	  signal Cfg_FrameTo   : std_logic_vector(Streams_g -1 downto 0);
185	  signal AWCache       : t_aslv4(2 downto 0) := (others => (others => '0'));
186	  signal AWProt        : t_aslv3(2 downto 0) := (others => (others => '0'));
187	  signal ARCache       : t_aslv4(2 downto 0) := (others => (others => '0'));
188	  signal ARProt        : t_aslv3(2 downto 0) := (others => (others => '0'));
189	  -- Status
190	  signal Stat_StrIrq      : std_logic_vector(Streams_g - 1 downto 0);
191	  signal Stat_StrLastWin  : WinType_a(Streams_g - 1 downto 0);
192	  signal Stat_IsArmed     : std_logic_vector(Streams_g - 1 downto 0);
193	  signal Stat_IsRecording : std_logic_vector(Streams_g - 1 downto 0);
194	
195	  -- Context Memory Connections
196	  signal CtxStr_Cmd  : ToCtxStr_t;
197	  signal CtxStr_Resp : FromCtx_t;
198	  signal CtxWin_Cmd  : ToCtxWin_t;
199	  signal CtxWin_Resp : FromCtx_t;
200	
201	  -- Others
202	  signal Sm_HasLast   : std_logic_vector(Streams_g - 1 downto 0);
203	  signal M_Axi_Areset : std_logic;      -- high active reset
204	  signal S_Axi_Areset : std_logic;      -- high active reset
205	
206	begin
207	
208	  M_Axi_Areset <= not M_Axi_Aresetn;
209	  S_Axi_Areset <= not S_Axi_Aresetn;
210	
211	  -- Sync quasi static vecctors
212	  sync_apc_reg : process(M_Axi_Aclk)
213	  begin
214	    if rising_edge(M_Axi_Aclk) then
215	      for i in 1 to 2 loop
216	        AWProt(i)  <= AWProt(i-1);
217	        AWCache(i) <= AWCache(i-1);
218	        ARProt(i)  <= ARProt(i-1);
219	        ARCache(i) <= ARCache(i-1);
220	      end loop;
221	    end if;
222	  end process;
223	  M_Axi_AwCache <= AWCache(2);
224	  M_Axi_AwProt  <= AWProt(2);
225	  M_Axi_ArCache <= ARCache(2);
226	  M_Axi_ArProt  <= ARProt(2);
227	
228	  --------------------------------------------
229	  -- Register Interface
230	  --------------------------------------------
231	  i_reg : entity work.psi_ms_daq_reg_axi
232	    generic map(
233	      Streams_g         => Streams_g,
234	      MaxWindows_g      => MaxWindows_g,
235	      AxiSlaveIdWidth_g => AxiSlaveIdWidth_g
236	    )
237	    port map(
238	      S_Axi_Aclk    => S_Axi_Aclk,
239	      S_Axi_Aresetn => S_Axi_Aresetn,
240	      S_Axi_ArId    => S_Axi_ArId,
241	      S_Axi_ArAddr  => S_Axi_ArAddr,
242	      S_Axi_Arlen   => S_Axi_Arlen,
243	      S_Axi_ArSize  => S_Axi_ArSize,
244	      S_Axi_ArBurst => S_Axi_ArBurst,
245	      S_Axi_ArLock  => S_Axi_ArLock,
246	      S_Axi_ArCache => S_Axi_ArCache,
247	      S_Axi_ArProt  => S_Axi_ArProt,
248	      S_Axi_ArValid => S_Axi_ArValid,
249	      S_Axi_ArReady => S_Axi_ArReady,
250	      S_Axi_RId     => S_Axi_RId,
251	      S_Axi_RData   => S_Axi_RData,
252	      S_Axi_RResp   => S_Axi_RResp,
253	      S_Axi_RLast   => S_Axi_RLast,
254	      S_Axi_RValid  => S_Axi_RValid,
255	      S_Axi_RReady  => S_Axi_RReady,
256	      S_Axi_AwId    => S_Axi_AwId,
257	      S_Axi_AwAddr  => S_Axi_AwAddr,
258	      S_Axi_AwLen   => S_Axi_AwLen,
259	      S_Axi_AwSize  => S_Axi_AwSize,
260	      S_Axi_AwBurst => S_Axi_AwBurst,
261	      S_Axi_AwLock  => S_Axi_AwLock,
262	      S_Axi_AwCache => S_Axi_AwCache,
263	      S_Axi_AwProt  => S_Axi_AwProt,
264	      S_Axi_AwValid => S_Axi_AwValid,
265	      S_Axi_AwReady => S_Axi_AwReady,
266	      S_Axi_WData   => S_Axi_WData,
267	      S_Axi_WStrb   => S_Axi_WStrb,
268	      S_Axi_WLast   => S_Axi_WLast,
269	      S_Axi_WValid  => S_Axi_WValid,
270	      S_Axi_WReady  => S_Axi_WReady,
271	      S_Axi_BId     => S_Axi_BId,
272	      S_Axi_BResp   => S_Axi_BResp,
273	      S_Axi_BValid  => S_Axi_BValid,
274	      S_Axi_BReady  => S_Axi_BReady,
275	      IrqOut        => Irq,
276	      AWCache       => AWCache(0),
277	      AWProt        => AWProt(0),
278	      ARCache       => ARCache(0),
279	      ARProt        => ARProt(0),
280	      PostTrig      => Cfg_PostTrig,
281	      Arm           => Cfg_Arm,
282	      IsArmed       => Stat_IsArmed,
283	      IsRecording   => Stat_IsRecording,
284	      RecMode       => Cfg_RecMode,
285	      ToDisable     => Cfg_ToDisable,
286	      FrameTo       => Cfg_FrameTo,
287	      ClkMem        => M_Axi_Aclk,
288	      RstMem        => M_Axi_Areset,
289	      CtxStr_Cmd    => CtxStr_Cmd,
290	      CtxStr_Resp   => CtxStr_Resp,
291	      CtxWin_Cmd    => CtxWin_Cmd,
292	      CtxWin_Resp   => CtxWin_Resp,
293	      InLevel       => InpSm_Level,
294	      StrIrq        => Stat_StrIrq,
295	      StrLastWin    => Stat_StrLastWin,
296	      StrEna        => Cfg_StrEna,
297	      GlbEna        => Cfg_GlbEna
298	    );
299	
300	  --------------------------------------------
301	  -- Input Logic Instantiation
302	  --------------------------------------------
303	  g_input : for str in 0 to Streams_g - 1 generate
304	    signal InRst    : std_logic;
305	    signal StrInput : std_logic_vector(StreamWidth_c(str) - 1 downto 0);
306	  begin
307	    -- Reset if stream is disabled
308	    InRst    <= M_Axi_Areset or not Cfg_StrEna(str) or not Cfg_GlbEna;
309	    StrInput <= Str_Data(str)(StrInput'range);
310	
311	    -- Instantiation
312	    i_input : entity work.psi_ms_daq_input
313	      generic map(
314	        StreamWidth_g       => StreamWidth_c(str),
315	        StreamBuffer_g      => StreamBuffer_c(str),
316	        StreamTimeout_g     => StreamTimeout_c(str),
317	        StreamClkFreq_g     => StreamClkFreq_c(str),
318	        StreamTsFifoDepth_g => StreamTsFifoDepth_c(str),
319	        StreamUseTs_g       => StreamUseTs_c(str),
320	        IntDataWidth_g      => IntDataWidth_g
321	      )
322	      port map(
323	        Str_Clk      => Str_Clk(str),
324	        Str_Vld      => Str_Vld(str),
325	        Str_Rdy      => Str_Rdy(str),
326	        Str_Data     => StrInput,
327	        Str_Trig     => Str_Trig(str),
328	        Str_Ts       => Str_Ts(str),
329	        ClkReg       => S_Axi_Aclk,
330	        RstReg       => S_Axi_Areset,
331	        PostTrigSpls => Cfg_PostTrig(str),
332	        Mode         => Cfg_RecMode(str),
333	        Arm          => Cfg_Arm(str),
334	        IsArmed      => Stat_IsArmed(str),
335	        IsRecording  => Stat_IsRecording(str),
336	        ToDisable    => Cfg_ToDisable(str),
337	        FrameTo      => Cfg_FrameTo(str),
338	        ClkMem       => M_Axi_Aclk,
339	        RstMem       => InRst,
340	        Daq_Vld      => InpDma_Vld(str),
341	        Daq_Rdy      => InpDma_Rdy(str),
342	        Daq_Data     => InpDma_Data(str),
343	        Daq_Level    => InpSm_Level(str),
344	        Daq_HasLast  => InpSm_HasTlast(str),
345	        Ts_Vld       => InpSm_TsVld(str),
346	        Ts_Rdy       => InpSm_TsRdy(str),
347	        Ts_Data      => InpSm_TsData(str)
348	      );
349	  end generate;
350	
351	  --------------------------------------------
352	  -- Control State Machine
353	  --------------------------------------------
354	  -- Detect end-of frame in input buffer or DMA buffer
355	  Sm_HasLast <= InpSm_HasTlast or DmaSm_HasLast;
356	
357	  -- Instantiation
358	  i_statemachine : entity work.psi_ms_daq_daq_sm
359	    generic map(
360	      Streams_g      => Streams_g,
361	      StreamPrio_g   => StreamPrio_c,
362	      StreamWidth_g  => StreamWidth_c,
363	      Windows_g      => MaxWindows_g,
364	      MinBurstSize_g => MinBurstSize_g,
365	      MaxBurstSize_g => MaxBurstSize_g
366	    )
367	    port map(
368	      Clk          => M_Axi_Aclk,
369	      Rst          => M_Axi_Areset,
370	      GlbEna       => Cfg_GlbEna,
371	      StrEna       => Cfg_StrEna,
372	      StrIrq       => Stat_StrIrq,
373	      StrLastWin   => Stat_StrLastWin,
374	      Inp_HasLast  => Sm_HasLast,
375	      Inp_Level    => InpSm_Level,
376	      Ts_Vld       => InpSm_TsVld,
377	      Ts_Rdy       => InpSm_TsRdy,
378	      Ts_Data      => InpSm_TsData,
379	      Dma_Cmd      => SmDma_Cmd,
380	      Dma_Cmd_Vld  => SmDma_CmdVld,
381	      Dma_Resp     => DmaSm_Resp,
382	      Dma_Resp_Vld => DmaSm_RespVld,
383	      Dma_Resp_Rdy => DmaSm_RespRdy,
384	      TfDone       => MemSm_Done,
385	      -- Context RAM connections
386	      CtxStr_Cmd   => CtxStr_Cmd,
387	      CtxStr_Resp  => CtxStr_Resp,
388	      CtxWin_Cmd   => CtxWin_Cmd,
389	      CtxWin_Resp  => CtxWin_Resp
390	    );
391	
392	  --------------------------------------------
393	  -- DMA Engine
394	  --------------------------------------------
395	  i_dma : entity work.psi_ms_daq_daq_dma
396	    generic map(
397	      Streams_g      => Streams_g,
398	      IntDataWidth_g => IntDataWidth_g
399	    )
400	    port map(
401	      Clk            => M_Axi_Aclk,
402	      Rst            => M_Axi_Areset,
403	      DaqSm_Cmd      => SmDma_Cmd,
404	      DaqSm_Cmd_Vld  => SmDma_CmdVld,
405	      DaqSm_Resp     => DmaSm_Resp,
406	      DaqSm_Resp_Vld => DmaSm_RespVld,
407	      DaqSm_Resp_Rdy => DmaSm_RespRdy,
408	      DaqSm_HasLast  => DmaSm_HasLast,
409	      Inp_Vld        => InpDma_Vld,
410	      Inp_Rdy        => InpDma_Rdy,
411	      Inp_Data       => InpDma_Data,
412	      Mem_CmdAddr    => DmaMem_CmdAddr,
413	      Mem_CmdSize    => DmaMem_CmdSize,
414	      Mem_CmdVld     => DmaMem_CmdVld,
415	      Mem_CmdRdy     => DmaMem_CmdRdy,
416	      Mem_DatData    => DmaMem_DatData,
417	      Mem_DatVld     => DmaMem_DatVld,
418	      Mem_DatRdy     => DmaMem_DatRdy
419	    );
420	
421	  --------------------------------------------
422	  -- Memory Interface
423	  --------------------------------------------
424	  i_memif : entity work.psi_ms_daq_axi_if
425	    generic map(
426	      IntDataWidth_g          => IntDataWidth_g,
427	      AxiDataWidth_g          => AxiDataWidth_g,
428	      AxiMaxBeats_g           => AxiMaxBurstBeats_g,
429	      AxiMaxOpenTrasactions_g => AxiMaxOpenTrasactions_g,
430	      MaxOpenCommands_g       => max(2, Streams_g), -- ISE tools implement memory as FFs for one stream. Reason is unkown, so we always implement two streams for resource optimization reasons.
431	      DataFifoDepth_g         => 1024,
432	      AxiFifoDepth_g          => AxiFifoDepth_g,
433	      RamBehavior_g           => "RBW"  -- Okay for Xilinx chips
434	    )
435	    port map(
436	      Clk           => M_Axi_Aclk,
437	      Rst_n         => M_Axi_Aresetn,
438	      Cmd_Addr      => DmaMem_CmdAddr,
439	      Cmd_Size      => DmaMem_CmdSize,
440	      Cmd_Vld       => DmaMem_CmdVld,
441	      Cmd_Rdy       => DmaMem_CmdRdy,
442	      Dat_Data      => DmaMem_DatData,
443	      Dat_Vld       => DmaMem_DatVld,
444	      Dat_Rdy       => DmaMem_DatRdy,
445	      Done          => MemSm_Done,
446	      M_Axi_AwAddr  => M_Axi_AwAddr,
447	      M_Axi_AwLen   => M_Axi_AwLen,
448	      M_Axi_AwSize  => M_Axi_AwSize,
449	      M_Axi_AwBurst => M_Axi_AwBurst,
450	      M_Axi_AwLock  => M_Axi_AwLock,
451	      M_Axi_AwCache => open, --M_Axi_AwCache
452	      M_Axi_AwProt  => open, --M_Axi_AwProt
453	      M_Axi_AwValid => M_Axi_AwValid,
454	      M_Axi_AwReady => M_Axi_AwReady,
455	      M_Axi_WData   => M_Axi_WData,
456	      M_Axi_WStrb   => M_Axi_WStrb,
457	      M_Axi_WLast   => M_Axi_WLast,
458	      M_Axi_WValid  => M_Axi_WValid,
459	      M_Axi_WReady  => M_Axi_WReady,
460	      M_Axi_BResp   => M_Axi_BResp,
461	      M_Axi_BValid  => M_Axi_BValid,
462	      M_Axi_BReady  => M_Axi_BReady,
463	      M_Axi_ArAddr  => M_Axi_ArAddr,
464	      M_Axi_ArLen   => M_Axi_ArLen,
465	      M_Axi_ArSize  => M_Axi_ArSize,
466	      M_Axi_ArBurst => M_Axi_ArBurst,
467	      M_Axi_ArLock  => M_Axi_ArLock,
468	      M_Axi_ArCache => open, --M_Axi_ArCache
469	      M_Axi_ArProt  => open, --M_Axi_ArProt
470	      M_Axi_ArValid => M_Axi_ArValid,
471	      M_Axi_ArReady => M_Axi_ArReady,
472	      M_Axi_RData   => M_Axi_RData,
473	      M_Axi_RResp   => M_Axi_RResp,
474	      M_Axi_RLast   => M_Axi_RLast,
475	      M_Axi_RValid  => M_Axi_RValid,
476	      M_Axi_RReady  => M_Axi_RReady
477	    );
478	
479	end;
